use proptest::prelude::*;
use serde_json::json;

use pi::extensions::{HostcallRequest, PiJsRuntime};

// Strategies for generating test inputs
fn hostcall_type_strategy() -> impl Strategy<Value = String> {
    prop_oneof\![
        Just("tool".to_string()),
        Just("exec".to_string()),
        Just("http".to_string()),
        Just("session".to_string()),
        Just("ui".to_string()),
        Just("events".to_string()),
        "[a-z]{1,10}".prop_map(String::from),  // Random invalid types
    ]
}

fn json_value_strategy() -> impl Strategy<Value = serde_json::Value> {
    prop_oneof\![
        Just(json\!(null)),
        Just(json\!(true)),
        Just(json\!(false)),
        any::<i64>().prop_map(|n| json\!(n)),
        any::<f64>().prop_filter("finite", |f| f.is_finite()).prop_map(|f| json\!(f)),
        ".*".prop_map(|s| json\!(s)),
        Just(json\!({})),
        Just(json\!([])),
    ]
}

#[derive(Debug, Clone)]
enum HostcallOp {
    ShowSpinner(String),
    StopSpinner(String),
    SetStatusLine(String),
    GetMessages,
    AppendMessage(String),
}

impl Arbitrary for HostcallOp {
    type Parameters = ();
    type Strategy = BoxedStrategy<Self>;

    fn arbitrary_with(_: Self::Parameters) -> Self::Strategy {
        prop_oneof\![
            ".*".prop_map(HostcallOp::ShowSpinner),
            "[a-f0-9-]{36}".prop_map(HostcallOp::StopSpinner),
            ".*".prop_map(HostcallOp::SetStatusLine),
            Just(HostcallOp::GetMessages),
            ".*".prop_map(HostcallOp::AppendMessage),
        ].boxed()
    }
}

impl HostcallOp {
    fn to_request(&self) -> HostcallRequest {
        match self {
            Self::ShowSpinner(msg) => HostcallRequest {
                hostcall_type: "ui".into(),
                method: "showSpinner".into(),
                args: json\!({ "message": msg }),
            },
            // ... other variants
        }
    }
}
